from flask import Flask, request, jsonify
import logging
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO)

# Dummy user database
users = {
    'user1': {'password_hash': generate_password_hash('password1'), 'email': 'user1@example.com'}
}

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')

    if username in users:
        user = users[username]
        if check_password_hash(user['password_hash'], password):
            log_login_attempt(username, user['email'], request.remote_addr, request.headers.get('User-Agent'))
            return jsonify({'message': 'Login successful'}), 200
        else:
            log_login_attempt(username, user['email'], request.remote_addr, request.headers.get('User-Agent'), success=False)
            return jsonify({'message': 'Invalid password'}), 401
    else:
        log_login_attempt(username, None, request.remote_addr, request.headers.get('User-Agent'), success=False)
        return jsonify({'message': 'Username not found'}), 404

def log_login_attempt(username, email, ip_address, user_agent, success=True):
    log_message = f"Username: {username}, Email: {email}, IP Address: {ip_address}, User Agent: {user_agent}, Success: {success}"
    logging.info(log_message)

if __name__ == '__main__':
    app.run(debug=True)